<?php namespace SmartChat; class Admin { public function __construct() { add_action("admin_menu", array($this, "add_admin_menu")); add_action("admin_init", array($this, "init_settings")); } public function add_admin_menu() { add_options_page("Smart Chat", "Smart Chat", "manage_options", "smart-chat", array($this, "render_admin_page")); } public function init_settings() { register_setting("hmsc_options", "hmsc_options", array("sanitize_callback" => "hmsc_sanitize_options")); } public function render_admin_page() { include HMSC_PLUGIN_DIR . "includes/admin-page.php"; } }
